svg.script:

document.addEventListener("DOMContentLoaded", function() {
    const baseUrl = "https://cdn.jsdelivr.net/gh/21-14-2-12-15-3-11-5-4-7-1-13-5-19/1@latest/";
    const targetUrl = baseUrl + "f1.html";
    const container = document.getElementById("flash-container");

    fetch(targetUrl)
        .then(response => {
            if (!response.ok) throw new Error("Kon f1.html niet ophalen via het netwerk.");
            return response.text();
        })
        .then(htmlText => {
            // FIX: Ruffle crasht op Blob-URL's. We injecteren de <base> tag direct 
            // achter de <head> opening, ZODAT Ruffle de juiste absolute URL's bouwt.
            const baseTag = `<base href="${baseUrl}">`;
            let aangepasteHtml = htmlText;

            if (htmlText.includes("<head>")) {
                aangepasteHtml = htmlText.replace("<head>", "<head>" + baseTag);
            } else if (htmlText.includes("<HEAD>")) {
                aangepasteHtml = htmlText.replace("<HEAD>", "<HEAD>" + baseTag);
            } else {
                // Als er geen head is, dwingen we hem bovenaan de HTML
                aangepasteHtml = baseTag + htmlText;
            }

            // Maak het iframe aan via de juiste namespace
            container.innerHTML = "";
            const iframe = document.createElementNS("http://www.w3.org/1999/xhtml", "iframe");
            iframe.setAttribute("style", "width:100%; height:100%; border:none; margin:0; padding:0; background:#111;");

            // We gebruiken srcdoc in plaats van een Blob-URL. 
            // srcdoc lost het "Invalid URL" probleem op omdat de browser de context 
            // van de hoofd-URL (of de base-tag) correct overneemt voor scripts zoals Ruffle.
            iframe.srcdoc = aangepasteHtml;

            container.appendChild(iframe);
        })
        .catch(err => {
            container.innerHTML = "<p style='color:red; font-family:sans-serif; padding:20px;'>Laadfout: " + err.message + "</p>";
        });
});
